wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(1900216188327005042)
,p_plug_name=>'Employees'
,p_static_id=>'employees_1'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2074200852440250129
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'  f.id,',
'  f.titulo     AS card_title,',
'  f.genero     AS card_text,',
'  f.nota_media AS card_subtext,',
'  (',
'    (SELECT COUNT(*)*3 FROM cf_usuario_filmes uf JOIN cf_filmes f2 ON uf.filme_id = f2.id',
'     WHERE uf.usuario_id = 1 AND f2.genero = f.genero)',
'    +',
'    (SELECT COUNT(*)*2 FROM cf_usuario_filmes uf JOIN cf_filmes f2 ON uf.filme_id = f2.id',
'     WHERE uf.usuario_id = 1 AND f2.diretor = f.diretor)',
'    + ROUND(f.nota_media)',
'  ) AS score_ia,',
'  CASE',
'    WHEN (SELECT COUNT(*) FROM cf_usuario_filmes uf JOIN cf_filmes f2 ON uf.filme_id = f2.id',
'          WHERE uf.usuario_id = 1 AND f2.diretor = f.diretor) > 0',
'    THEN ''Curte '' || f.diretor',
'    ELSE ''Gosto por '' || f.genero',
'  END AS card_badge',
'FROM cf_filmes f',
'WHERE f.id NOT IN (SELECT filme_id FROM cf_usuario_filmes WHERE usuario_id = 1)',
'ORDER BY score_ia DESC',
'FETCH FIRST 6 ROWS ONLY'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
,p_created_on=>wwv_flow_imp.dz('20260523191842Z')
,p_updated_on=>wwv_flow_imp.dz('20260523192701Z')
,p_created_by=>'RM559369@FIAP.COM.BR'
,p_updated_by=>'RM559369@FIAP.COM.BR'
);
